        if entry != pending {
            if let Err(err) = handle_futex_death(entry, offset) {
                debug!("skip invalid robust futex entry {entry:p}: {err:?}");
            }
        }
        entry = next_entry;

        limit -= 1;
        if limit == 0 {
            debug!("stop robust list cleanup after reaching traversal limit");
            break;
        }
        axtask::yield_now();
    }

    Ok(())
}
