pub fn sys_getitimer(which: i32, value: *mut itimerval) -> AxResult<isize> {
    let ty = ITimerType::from_repr(which).ok_or(AxError::InvalidInput)?;
    let (it_interval, it_value) = current().as_thread().time.borrow().get_itimer(ty);

    value.vm_write(itimerval {
        it_interval: timeval::from_time_value(it_interval),
        it_value: timeval::from_time_value(it_value),
    })?;
    Ok(0)
}

pub fn sys_setitimer(
    which: i32,
    new_value: *const itimerval,
    old_value: *mut itimerval,
) -> AxResult<isize> {
    let ty = ITimerType::from_repr(which).ok_or(AxError::InvalidInput)?;
    let curr = current();

    let (interval, remained) = match new_value.nullable() {
        Some(new_value) => {
            // FIXME: AnyBitPattern
            let new_value = unsafe { new_value.vm_read_uninit()?.assume_init() };
            (
                new_value.it_interval.try_into_time_value()?.as_nanos() as usize,
                new_value.it_value.try_into_time_value()?.as_nanos() as usize,
            )
        }
        None => (0, 0),
    };

    debug!("sys_setitimer <= type: {ty:?}, interval: {interval:?}, remained: {remained:?}");

    let old = curr
        .as_thread()
        .time
        .borrow_mut()
        .set_itimer(ty, interval, remained);

    if let Some(old_value) = old_value.nullable() {
        old_value.vm_write(itimerval {
            it_interval: timeval::from_time_value(old.0),
            it_value: timeval::from_time_value(old.1),
        })?;
    }
    Ok(0)
}

pub fn sys_timer_create(
    clock_id: __kernel_clockid_t,
    sevp: *const sigevent,
    timerid: *mut __kernel_timer_t,
) -> AxResult<isize> {
    let clock = PosixTimerClock::from_clock_id(clock_id)?;
    let curr = current();
    let proc_data = &curr.as_thread().proc_data;
    let owner_pid = proc_data.proc.pid();
    let (notification, signal_value) = parse_sigevent(sevp, owner_pid)?;
    let timer = PosixTimer::new(clock, owner_pid, notification, signal_value);
    let id = proc_data.posix_timers.add(timer)?;

    if let Err(err) = timerid.vm_write(id as __kernel_timer_t) {
        let _ = proc_data.posix_timers.delete(id);
        return Err(err.into());
    }
    Ok(0)
}

pub fn sys_timer_settime(
    timerid: __kernel_timer_t,
    flags: i32,
    new_value: *const itimerspec,
    old_value: *mut itimerspec,
) -> AxResult<isize> {
    if flags & !(TIMER_ABSTIME as i32) != 0 {
        return Err(AxError::InvalidInput);
    }

    let timer = current().as_thread().proc_data.posix_timers.get(timerid)?;
    let new_value = unsafe { new_value.vm_read_uninit()?.assume_init() }.try_into_timer_spec()?;
    let old = timer.set_time(flags & TIMER_ABSTIME as i32 != 0, new_value);
    if let Some(old_value) = old_value.nullable() {
        old_value.vm_write(itimerspec::from_timer_spec(old))?;
    }
    Ok(0)
}

