fn parse_sigevent(
    sevp: *const sigevent,
    owner_pid: u32,
) -> AxResult<(PosixTimerNotification, PosixTimerSignalValue)> {
    let Some(sevp) = sevp.nullable() else {
        return Ok((
            PosixTimerNotification::Process {
                signo: Signo::SIGALRM,
            },
            zero_sigval(),
        ));
    };

    let event = unsafe { sevp.vm_read_uninit()?.assume_init() };
    let notification = match event.sigev_notify as u32 {
        SIGEV_NONE => PosixTimerNotification::None,
        SIGEV_SIGNAL => PosixTimerNotification::Process {
            signo: parse_timer_signo(event.sigev_signo)?,
        },
        SIGEV_THREAD_ID => {
            let signo = parse_timer_signo(event.sigev_signo)?;
            let raw_tid = unsafe { event._sigev_un._tid };
            if raw_tid <= 0 {
                return Err(AxError::InvalidInput);
            }
            let tid = raw_tid as u32;
            send_signal_to_thread(Some(owner_pid), tid, None)?;
            PosixTimerNotification::Thread { tid, signo }
        }
        SIGEV_THREAD => return Err(AxError::InvalidInput),
        _ => return Err(AxError::InvalidInput),
    };
    Ok((
        notification,
        PosixTimerSignalValue::from_sigval(event.sigev_value),
    ))
}

fn parse_timer_signo(signo: i32) -> AxResult<Signo> {
    if !(1..=64).contains(&signo) {
        return Err(AxError::InvalidInput);
    }
    Signo::from_repr(signo as u8).ok_or(AxError::InvalidInput)
}

