fn sleep_impl(clock: impl Fn() -> TimeValue, dur: TimeValue) -> TimeValue {
    debug!("sleep_impl <= {dur:?}");

    let start = clock();

    // TODO: currently ignoring concrete clock type
    // We detect EINTR manually if the slept time is not enough.
    let _ = block_on(interruptible(sleep(dur)));

    clock() - start
}

/// Sleep some nanoseconds
pub fn sys_nanosleep(req: *const timespec, rem: *mut timespec) -> AxResult<isize> {
    // FIXME: AnyBitPattern
    let req = unsafe { req.vm_read_uninit()?.assume_init() }.try_into_time_value()?;
    debug!("sys_nanosleep <= req: {req:?}");

    let actual = sleep_impl(axhal::time::monotonic_time, req);

    if let Some(diff) = req.checked_sub(actual) {
        debug!("sys_nanosleep => rem: {diff:?}");
        if let Some(rem) = rem.nullable() {
            rem.vm_write(timespec::from_time_value(diff))?;
        }
        Err(AxError::Interrupted)
    } else {
        Ok(0)
    }
}

pub fn sys_clock_nanosleep(
    clock_id: __kernel_clockid_t,
    flags: u32,
    req: *const timespec,
    rem: *mut timespec,
) -> AxResult<isize> {
    let clock = match clock_id as u32 {
        CLOCK_REALTIME => axhal::time::wall_time,
        CLOCK_MONOTONIC => axhal::time::monotonic_time,
        _ => {
            warn!("Unsupported clock_id: {clock_id}");
            return Err(AxError::InvalidInput);
        }
    };

    let req = unsafe { req.vm_read_uninit()?.assume_init() }.try_into_time_value()?;
    debug!("sys_clock_nanosleep <= clock_id: {clock_id}, flags: {flags}, req: {req:?}");

    let dur = if flags & TIMER_ABSTIME != 0 {
        req.saturating_sub(clock())
    } else {
        req
    };

    let actual = sleep_impl(clock, dur);

    if let Some(diff) = dur.checked_sub(actual) {
        debug!("sys_clock_nanosleep => rem: {diff:?}");
        if let Some(rem) = rem.nullable() {
            rem.vm_write(timespec::from_time_value(diff))?;
        }
        Err(AxError::Interrupted)
    } else {
        Ok(0)
    }
}

pub fn sys_sched_getaffinity(pid: i32, cpusetsize: usize, user_mask: *mut u8) -> AxResult<isize> {
    if cpusetsize * 8 < axhal::cpu_num() {
        return Err(AxError::InvalidInput);
    }

    // TODO: support other threads
    if pid != 0 {
        return Err(AxError::OperationNotPermitted);
    }

    let mask = current().cpumask();
    let mask_bytes = mask.as_bytes();

    vm_write_slice(user_mask, mask_bytes)?;

    Ok(mask_bytes.len() as _)
}

pub fn sys_sched_setaffinity(
    _pid: i32,
    cpusetsize: usize,
    user_mask: *const u8,
) -> AxResult<isize> {
    let size = cpusetsize.min(axhal::cpu_num().div_ceil(8));
    let user_mask = vm_load(user_mask, size)?;
    let mut cpu_mask = AxCpuMask::new();

    for i in 0..(size * 8).min(axhal::cpu_num()) {
        if user_mask[i / 8] & (1 << (i % 8)) != 0 {
            cpu_mask.set(i, true);
        }
    }

    // TODO: support other threads
    axtask::set_current_affinity(cpu_mask);

    Ok(0)
}

fn task_for_scheduler_pid(pid: i32) -> AxResult<axtask::AxTaskRef> {
    if pid < 0 {
        return Err(AxError::InvalidInput);
    }
    get_task(pid as _)
}

fn priority_bounds(policy: i32) -> AxResult<(i32, i32)> {
    match policy {
        SCHED_OTHER => Ok((0, 0)),
        policy if policy == SCHED_BATCH as i32 || policy == SCHED_IDLE as i32 => Ok((0, 0)),
        policy if policy == SCHED_FIFO as i32 || policy == SCHED_RR as i32 => Ok((1, 99)),
        policy if policy == SCHED_DEADLINE as i32 => Err(AxError::InvalidInput),
        _ => Err(AxError::InvalidInput),
    }
}

fn validate_sched_priority(policy: i32, priority: i32) -> AxResult<()> {
    let (min, max) = priority_bounds(policy)?;
    if (min..=max).contains(&priority) {
        Ok(())
    } else {
        Err(AxError::InvalidInput)
    }
}

fn parse_scheduler_policy(policy: i32) -> AxResult<(i32, bool)> {
    let reset_flag = SCHED_RESET_ON_FORK as i32;
    let reset_on_fork = policy & reset_flag != 0;
    let base_policy = policy & !reset_flag;
    priority_bounds(base_policy)?;
    Ok((base_policy, reset_on_fork))
}

fn read_sched_param(param: *const SchedParam) -> AxResult<SchedParam> {
    Ok(unsafe { param.vm_read_uninit()?.assume_init() })
}

pub fn sys_sched_getscheduler(pid: i32) -> AxResult<isize> {
    let task = task_for_scheduler_pid(pid)?;
    Ok(task.as_thread().sched_policy() as _)
}

pub fn sys_sched_setscheduler(pid: i32, policy: i32, param: *const SchedParam) -> AxResult<isize> {
    let task = task_for_scheduler_pid(pid)?;
    let param = read_sched_param(param)?;
    let (base_policy, reset_on_fork) = parse_scheduler_policy(policy)?;

    validate_sched_priority(base_policy, param.sched_priority)?;
    task.as_thread()
        .set_scheduler(base_policy, param.sched_priority, reset_on_fork);

    Ok(0)
}

pub fn sys_sched_getparam(pid: i32, param: *mut SchedParam) -> AxResult<isize> {
    let task = task_for_scheduler_pid(pid)?;
    param.vm_write(SchedParam {
        sched_priority: task.as_thread().sched_priority(),
    })?;
    Ok(0)
}

pub fn sys_sched_setparam(pid: i32, param: *const SchedParam) -> AxResult<isize> {
    let task = task_for_scheduler_pid(pid)?;
    let param = read_sched_param(param)?;
    let policy = task.as_thread().sched_policy();

    validate_sched_priority(policy, param.sched_priority)?;
    task.as_thread().set_sched_priority(param.sched_priority);

    Ok(0)
}

pub fn sys_sched_get_priority_max(policy: i32) -> AxResult<isize> {
    let (_, max) = priority_bounds(policy)?;
    Ok(max as _)
}

pub fn sys_sched_get_priority_min(policy: i32) -> AxResult<isize> {
    let (min, _) = priority_bounds(policy)?;
    Ok(min as _)
}

pub fn sys_sched_rr_get_interval(pid: i32, tp: *mut timespec) -> AxResult<isize> {
    let _task = task_for_scheduler_pid(pid)?;
    tp.vm_write(timespec {
        tv_sec: 0,
        tv_nsec: 10_000_000,
    })?;
    Ok(0)
}

pub fn sys_getpriority(which: u32, who: u32) -> AxResult<isize> {
    debug!("sys_getpriority <= which: {which}, who: {who}");

    match which {
        PRIO_PROCESS => {
            if who != 0 {
                let _proc = get_process_data(who)?;
            }
            Ok(20)
        }
        PRIO_PGRP => {
            if who != 0 {
                let _pg = get_process_group(who)?;
            }
            Ok(20)
        }
        PRIO_USER => {
            if who == 0 {
                Ok(20)
            } else {
                Err(AxError::NoSuchProcess)
            }
        }
        _ => Err(AxError::InvalidInput),
    }
}

use alloc::{borrow::Cow, sync::Arc};
use core::{
